from flask import Flask, render_template, redirect, url_for, request
import os
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'

# Utility functions to read and write data files based on schemas

def parse_books():
    books_path = os.path.join(DATA_DIR, 'books.txt')
    books = []
    if os.path.exists(books_path):
        with open(books_path, 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) < 8:
                    continue
                book = {
                    'book_id': int(parts[0]),
                    'title': parts[1],
                    'author': parts[2],
                    'isbn': parts[3],
                    'category': parts[4],
                    'price': float(parts[5]),
                    'stock': int(parts[6]),
                    'description': parts[7]
                }
                books.append(book)
    return books


def parse_categories():
    categories_path = os.path.join(DATA_DIR, 'categories.txt')
    categories = []
    if os.path.exists(categories_path):
        with open(categories_path, 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) < 3:
                    continue
                category = {
                    'category_id': int(parts[0]),
                    'category_name': parts[1],
                    'description': parts[2]
                }
                categories.append(category)
    return categories


def parse_cart():
    cart_path = os.path.join(DATA_DIR, 'cart.txt')
    cart = []
    if os.path.exists(cart_path):
        with open(cart_path, 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) < 4:
                    continue
                item = {
                    'cart_id': int(parts[0]),
                    'book_id': int(parts[1]),
                    'quantity': int(parts[2]),
                    'added_date': parts[3]
                }
                cart.append(item)
    return cart


def write_cart(cart):
    cart_path = os.path.join(DATA_DIR, 'cart.txt')
    try:
        with open(cart_path, 'w', encoding='utf-8') as f:
            for item in cart:
                line = f"{item['cart_id']}|{item['book_id']}|{item['quantity']}|{item['added_date']}\n"
                f.write(line)
        return True
    except Exception:
        return False


